"""
mkt-original | deuteronomy | ch26–27 fill
present: ch26:v5,17; ch27:v5,26 — 41 missing verses
run: python3 scripts/zc-original-deuteronomy-26-27-fill.py

Key decisions:
- ch26: First-fruits confession (vv1-11), third-year tithe declaration (vv12-15), covenant avowal (vv16-19)
- ch27: Ebal altar ceremony (vv1-10), twelve tribes split (vv11-13), dodecalogue of curses (vv15-25)
- Bold Hebrew transliteration matches earlier Deut entries; academic transliteration in <em> parens
- Ch26:v5 (Aramean creed) already present — skipped
- Ch27:v5 (uncut-stone altar) and v26 (climactic curse) already present — skipped
"""

import json, pathlib

ROOT = pathlib.Path(__file__).resolve().parent.parent

def load_comm(layer, book):
    p = ROOT / 'data' / 'commentary' / f'mkt-{layer}' / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(layer, book, data):
    p = ROOT / 'data' / 'commentary' / f'mkt-{layer}' / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

DEUT = {
  "26": {
    "1": "<p><strong>veha'ya ki-tavo el-ha'aretz asher YHWH Eloheicha noten lecha nachalah uvarishtah veyashavta vah</strong> (<em>wĕhāyâ kî-tāb̠ōʾ ʾel-hāʾāreṣ ʾăšer Yhwh ʾĕlōhêkā nōtēn lĕkā nĕḥālâ ûb̠ĕrišhtāh wĕyāšab̠tā b̠āh</em>): 'And it shall be when you come into the land that the LORD your God gives you as an inheritance, and you possess it and dwell in it.' The verse frames the first-fruits ritual as a future obligation tied to the gift of land. <em>Nachalah</em> (inheritance, portion): the land is not property acquired but a covenant inheritance granted — the same term used for the tribal allotments and for Israel's own status as YHWH's <em>nachalah</em> (cf. Deut 4:20). <em>Uvarishtah</em> (you possess it) from <em>yarash</em>: to dispossess, to inherit by taking possession. The first-fruits law is prospective — a liturgical response embedded into the act of settlement itself, so that the memory of gift does not erode into an assumption of entitlement.</p>",
    "2": "<p><strong>velakachta mereishit kol-pri ha'adamah asher tavi me'artzecha... vesamt batel vehalacht el-hamaqom asher yivchar YHWH Eloheicha leshakken shemo sham</strong> (<em>wĕlāqaḥtā mērēʾšît kol-pĕrî hāʾădāmâ... wĕśamtā b̠aṭene wĕhālaḵtā ʾel-hammāqôm ʾăšer yib̠ḥar Yhwh ʾĕlōhêkā lĕšakkēn šĕmô šām</em>): Take the first of all the fruit of the ground and put it in a basket, then go to the place that YHWH shall choose to make his name dwell there. <em>Reishit</em> (first, beginning): the first of the harvest is set apart — not because it is better but because it is <em>first</em>, a synecdoche for the whole. <em>Batel</em> (basket, container): the portable vessel for presenting the offering. <em>Hamaqom asher yivchar</em> (the place YHWH shall choose): the centralizing formula of Deuteronomy, pointing to Jerusalem and the Temple. First-fruits are not distributed locally but brought to the singular sanctuary — the spatial corollary of monotheism.</p>",
    "3": "<p><strong>uvata el-hakohen asher yihyeh bayamim hahem ve'amarta elav higadeti hayom l'YHWH Eloheicha ki-vati el-ha'aretz asher nishba YHWH la'avoteinu latet lanu</strong> (<em>ûb̠āʾtā ʾel-hakkōhēn ʾăšer yihyê b̠ayyāmîm hāhēm wĕʾāmartā ʾēlāyw higgadtî hayyôm lYhwh ʾĕlōhêkā kî-b̠āʾtî ʾel-hāʾāreṣ ʾăšer nišbaʿ Yhwh lāʾăb̠ôtênû lātēt lānû</em>): 'And you shall come to the priest who is in office in those days and say to him, I declare today to the LORD your God that I have come into the land that the LORD swore to our fathers to give us.' <em>Higadeti</em> (I declare, I report, I make known) from <em>nagad</em>: the formal declaration is performative — the gift of land is publicly acknowledged as a fulfilled oath. <em>Nishba</em> (swore): the oath to the patriarchs (Gen 12:7; 13:15; 15:18) has been kept; the worshipper's presence at the sanctuary with first-fruits is its proof.</p>",
    "4": "<p><strong>velakach hakohen hatel miyadecha vehinichah lifnei mizbach YHWH Eloheicha</strong> (<em>wĕlāqaḥ hakkōhēn haṭṭene miyyāḏĕkā wĕhinnîḥô lip̄nê mizbēaḥ Yhwh ʾĕlōhêkā</em>): 'And the priest shall take the basket from your hand and set it down before the altar of the LORD your God.' The priest's action mediates the transfer: the basket moves from the hand of the worshipper to the presence of YHWH at the altar. <em>Hinichah lifnei</em> (set it down before): placement before the altar is the spatial equivalent of presenting it to YHWH himself — the altar as the meeting point of human offering and divine presence. The priest functions here not as a sacrificial agent but as a courier of the worshipper's declaration.</p>",
    "6": "<p><strong>vayarei'u otanu haMitzrim vaye'anunu vayitnu aleinu avodah kashah</strong> (<em>wayyārēʿû ʾōtānû hammiṣrîm wayyĕʿannûnû wayyitĕnû ʿālênû ʿăb̠ôdâ qāšâ</em>): 'And the Egyptians treated us harshly and afflicted us, and laid on us hard labor.' Part of the recited creed (vv. 5-10). Three verbs of oppression: <em>vayarei'u</em> (made things bad for us, treated us ill — <em>ra'a</em>), <em>vaye'anunu</em> (afflicted us — <em>anah</em>: to humble, to oppress), <em>avodah kashah</em> (hard labor — <em>kasha</em>: harsh, severe). The liturgical creed encodes the memory of bondage so that prosperity never erases the knowledge of what Israel was without YHWH's intervention.</p>",
    "7": "<p><strong>vanitztaq el-YHWH Elohei avoteinu vayishma YHWH et-qoleinu vayar et-onyenu ve'et-amaleinu ve'et-lachatzenu</strong> (<em>wanniṣʿaq ʾel-Yhwh ʾĕlōhê ʾăb̠ôtênû wayyišmaʿ Yhwh ʾet-qōlênû wayyarʾ ʾet-ʿonyênû wĕʾet-ʿămālênû wĕʾet-laḥăṣênû</em>): 'And we cried to the LORD, the God of our fathers, and the LORD heard our voice, and saw our affliction, our toil, and our oppression.' Three terms for suffering: <em>oni</em> (affliction, humiliation), <em>amal</em> (toil, travail), <em>lachatz</em> (oppression, pressure). The creed emphasizes YHWH's perception — he heard (<em>shama</em>) and saw (<em>ra'ah</em>) — the divine attention that precedes rescue. This forms the theological grammar of the Exodus: cry → YHWH hears and sees → deliverance.</p>",
    "8": "<p><strong>vayotzi'enu YHWH miMitzrayim beyad chazakah uvizroa netuyah uvemorah gadol uviotot uvemoftim</strong> (<em>wayyôṣiʾênû Yhwh mimmîṣrāyim b̠ĕyād ḥăzāqâ ûb̠izrôaʿ nĕṭûyâ ûb̠emôrāʾ gādôl ûb̠ʾōtôt ûb̠emōp̄tîm</em>): 'And the LORD brought us out of Egypt with a mighty hand and an outstretched arm, with great deeds of terror, with signs and wonders.' The four-fold epitome of the Exodus: <em>yad chazakah</em> (mighty hand), <em>zroa netuyah</em> (outstretched arm), <em>morah gadol</em> (great awe/terror), <em>otot umoftim</em> (signs and wonders). This formula recurs throughout Deuteronomy (4:34; 7:19; 11:2) as the canonical summary of YHWH's redemptive act. The creed performs the Exodus anew each time it is spoken — liturgical memory as identity formation.</p>",
    "9": "<p><strong>vayevi'enu el-hamaqom hazeh vayiten lanu et-ha'aretz hazot eretz zavat chalav udvash</strong> (<em>wayyĕb̠iʾênû ʾel-hammāqôm hazzê wayyittēn-lānû ʾet-hāʾāreṣ hazzōʾt ʾereṣ zāb̠at ḥālāb̠ ûd̠ĕb̠aš</em>): 'And he brought us to this place and gave us this land, a land flowing with milk and honey.' The creed reaches its destination: from Aram to Egypt to the wilderness to <em>this place</em>. <em>Eretz zavat chalav udvash</em> (land flowing with milk and honey): the covenant formula first spoken in Exod 3:8 and repeated throughout Deuteronomy. <em>Zavat</em> from <em>zub</em> (to flow): the land is abundant in pastoral and agricultural produce — milk (livestock) and honey (wild honey or date honey, <em>dibs</em>). The creed culminates in gift: YHWH's action ends not in rescue alone but in bestowal.</p>",
    "10": "<p><strong>ve'atah hinei heveti et-reishit pri ha'adamah asher-natata li YHWH vehinhachto lifnei YHWH Eloheicha vehishtachavita lifnei YHWH Eloheicha</strong> (<em>wĕʿattâ hinnê hēb̠ēʾtî ʾet-rēʾšît pĕrî hāʾădāmâ ʾăšer-nātattā lî Yhwh wĕhinnăḥtô lip̄nê Yhwh ʾĕlōhêkā wĕhištaḥăwîtā lip̄nê Yhwh ʾĕlōhêkā</em>): 'And now, behold, I have brought the first of the fruit of the ground, which you, O LORD, have given me. And you shall set it down before the LORD your God and worship before the LORD your God.' The creed pivots to the present act: the historical recitation (vv. 5-9) ends in <em>ve'atah</em> (and now, therefore) — the past determines the present obligation. <em>Hinei heveti</em> (here I bring): the gesture of presentation is the embodied response to the history just recited. <em>Vehishtachavita</em> (and you shall bow down/worship): the presentation culminates in prostration — acknowledgment of lordship.</p>",
    "11": "<p><strong>vesimachta bechol-hatov asher natan lecha YHWH Eloheicha ulveitecha atta vehaLevi veha'ger asher beqirbecha</strong> (<em>wĕśāmaḥtā b̠ĕḵol-haṭṭôb̠ ʾăšer nātan lĕkā Yhwh ʾĕlōhêkā ûlĕb̠êtĕkā ʾattâ wĕhalLēwî wĕhagēr ʾăšer b̠ĕqirb̠ĕkā</em>): 'And you shall rejoice in all the good that the LORD your God has given to you and to your house, you, and the Levite, and the sojourner who is among you.' <em>Vesimachta</em> (and you shall rejoice): the ritual of first-fruits ends not in solemn duty but in communal joy. Three parties rejoice together: the Israelite householder (<em>atta uveitekha</em>), the Levite (who has no land allotment), and the <em>ger</em> (sojourner/stranger). The economic vulnerability of the Levite and the alien makes their inclusion in covenant joy theologically significant — the gift of land extends its circle beyond those who legally hold it.</p>",
    "12": "<p><strong>ki techale la'aser et-kol-ma'aser tevuatecha bashanah hashlishit shenat hama'aser venatata laLevi lager layatom velalmana ve'achlu vishveicha vesave'u</strong> (<em>kî tĕḵallê laʿaśēr ʾet-kol-maʿăśar tĕb̠ûʾātĕkā baššānâ haššĕlîšît šĕnat hamma'ăśēr wĕnātattā lalLēwî laggēr lāyyātôm wĕlāʾalmānâ wĕʾāḵĕlû b̠išʿārêkā wĕśāb̠ĕʿû</em>): 'When you have finished paying all the tithe of your produce in the third year, which is the year of tithing, you shall give it to the Levite, the sojourner, the fatherless, and the widow, that they may eat within your towns and be filled.' The third-year tithe (<em>ma'aser sheni</em> variant: the triennial tithe for the poor, distinct from the annual tithe consumed at the sanctuary) redirects the offering to local distribution. The four-fold welfare beneficiary list: Levite, <em>ger</em>, <em>yatom</em> (orphan), <em>almanah</em> (widow) — the same quartet of the vulnerable that recurs throughout Deuteronomy (cf. 14:29; 16:11, 14; 24:17-19). The law institutionalizes welfare as a tithe-obligation, not voluntary charity.</p>",
    "13": "<p><strong>ve'amarta lifnei YHWH Eloheicha bi'arti haqodesh min-habayit vegam netativ laLevi velager layatom velalmana kechol-mitzvaticha asher tzivitani lo-avarti mimitzvotelcha velo-shachachti</strong> (<em>wĕʾāmartā lip̄nê Yhwh ʾĕlōhêkā biʿartî haqqōḏeš min-hab̠bayit wĕgam nĕtattîw lalLēwî wĕlaggēr layyātôm wĕlāʾalmānâ kĕḵol-miṣwātĕkā ʾăšer ṣiwwîtānî lōʾ-ʿāb̠artî mimmîṣwōtêkā wĕlōʾ šāḵāḥtî</em>): 'Then you shall say before the LORD your God, I have removed the sacred portion (<em>haqodesh</em>) out of my house, and moreover I have given it to the Levite, the sojourner, the fatherless, and the widow, according to all your commandment that you have commanded me. I have not transgressed any of your commandments, nor have I forgotten any of them.' The tithe declaration is a covenant compliance report. <em>Bi'arti haqodesh</em> (I have cleared out the sacred portion): <em>bi'er</em> means to remove, clear out, consume entirely — the tithe must be <em>completely distributed</em>, not stored or hoarded. The declaration is first-person, specific, and addressed directly to YHWH — a covenant audit conducted in divine presence.</p>",
    "14": "<p><strong>lo-achalti ve'oni mimenu velo-bi'arti mimenu betame'a velo-natati mimenu leMet shamati beqol YHWH Elohai asiti kechol asher tzivitani</strong> (<em>lōʾ-ʾāḵaltî b̠ĕʾônî mimmennû wĕlōʾ-b̠iʿartî mimmennû b̠ĕṭāmēʾ wĕlōʾ-nātattî mimmennû lāmēt šāmaʿtî b̠ĕqôl Yhwh ʾĕlōhāy ʿāśîtî kĕḵōl ʾăšer ṣiwwîtānî</em>): 'I have not eaten of the tithe while I was mourning, or removed any of it while I was unclean, or offered any of it to the dead. I have obeyed the voice of the LORD my God. I have done according to all that you have commanded me.' Three negative prohibitions — not eaten in mourning (<em>oni</em>), not handled while ritually impure (<em>tame'</em>), not used it in funerary offerings (<em>laMet</em>, for the dead). Each addresses a specific contamination risk: grief-eating might compromise the joyful character of the offering; ritual impurity would defile a sacred portion; funerary use would blend covenant worship with ancestor cult. The declaration is a formal purity oath.</p>",
    "15": "<p><strong>hashkifah mimeon kodshecha min-hashamayim uvarech et-amecha et-Yisrael ve'et ha'adamah asher natata lanu ka'asher nishbata la'avoteinu eretz zavat chalav udvash</strong> (<em>hašqîp̄â mimmĕʿôn qoḏšĕkā min-haššāmayim ûb̠āreḵ ʾet-ʿammĕkā ʾet-Yiśrāʾēl wĕʾēt hāʾădāmâ ʾăšer nātattā lānû kāʾăšer nišbaʿtā lāʾăb̠ôtênû ʾereṣ zāb̠at ḥālāb̠ ûd̠ĕb̠aš</em>): 'Look down from your holy habitation, from heaven, and bless your people Israel and the ground that you have given us, as you swore to our fathers, a land flowing with milk and honey.' <em>Hashkifah</em> (look down): the verb <em>shaqaf</em> implies a peering downward from above, the posture of a sovereign surveying his domain. <em>Me'on kodshecha</em> (your holy habitation): heaven itself is YHWH's dwelling — the sanctuary on earth is a copy of the heavenly archetype (cf. Exod 25:40; Heb 9:24). The worshipper who has completed the tithe now appeals from the completed act on earth to YHWH's vantage in heaven — compliance enables intercession.</p>",
    "16": "<p><strong>hayom hazeh YHWH Eloheicha metzavecha la'asot et-hachuqqim ha'eleh ve'et-hamishpatim ushemartem va'asitem otam bechol-levavecha uvechol-nafshecha</strong> (<em>hayyôm hazzê Yhwh ʾĕlōhêkā mĕṣawwĕkā laʿăśôt ʾet-haḥuqqîm hāʾēllê wĕʾet-hamišpāṭîm ûšĕmartem waʿăśîtem ʾôtām b̠ĕḵol-lĕb̠āb̠ĕkā ûb̠ĕḵol-nap̄šĕkā</em>): 'This day the LORD your God commands you to do these statutes and rules. You shall therefore be careful to do them with all your heart and with all your soul.' <em>Hayom hazeh</em> (this day): the Deuteronomic emphasis on contemporaneity — the commandment is given not to the wilderness generation alone but to every generation that hears it (cf. 5:3; 29:14). The <em>Shema</em> vocabulary: <em>bechol-levavecha uvechol-nafshecha</em> (with all your heart and with all your soul) — covenant obedience requires total disposition, not merely external compliance.</p>",
    "18": "<p><strong>veYHWH he'emircha hayom lihyot lo leam segulah ka'asher diber lach velishmor kol-mitzvotav</strong> (<em>wYhwh heʾemîrĕkā hayyôm lihyôt lô lĕʿam sĕgullâ kāʾăšer dib̠ber lāk wĕlišmôr kol-miṣwōtāyw</em>): 'And the LORD has avouched you this day to be a people for his treasured possession, as he has promised you, and to keep all his commandments.' <em>He'emircha</em>: as with v17, the Hiphil of <em>amar</em> means to cause to declare or to declare solemnly — YHWH has formally declared Israel to be his. <em>Am segulah</em> (treasured people, people of special possession): <em>segulah</em> in Akkadian means moveable personal wealth of the king — the private treasure of the sovereign. Israel is not merely YHWH's people but his personal treasure (cf. Exod 19:5; Mal 3:17). The covenant is a mutual declaration of exclusive belonging.</p>",
    "19": "<p><strong>ultetecha elyon al kol-hagoyim asher asah litehilah uleShem uletifaret ulihyot am kadosh l'YHWH Eloheicha ka'asher diber</strong> (<em>ûlĕtittĕkā ʿelyôn ʿal kol-haggôyîm ʾăšer ʿāśâ litĕhillâ ûlĕšēm ûlĕtip̄ʾāret wĕlihyôt ʿam qāḏôš lYhwh ʾĕlōhêkā kāʾăšer dib̠ber</em>): 'And he will set you in praise and in fame and in honor high above all nations that he has made, and that you shall be a people holy to the LORD your God, as he has spoken.' Three-fold elevation: <em>tehilah</em> (praise, renown), <em>shem</em> (name, reputation), <em>tifaret</em> (glory, splendor) — Israel is to be the showcase of YHWH's covenant faithfulness among the nations. <em>Am qadosh</em> (holy people): <em>qadosh</em> (set apart, consecrated) — Israel's holiness is derivative, not intrinsic; it flows from YHWH's sanctifying choice. The NT reapplies this language to the church as the new covenant people (1 Pet 2:9).</p>"
  },
  "27": {
    "1": "<p><strong>vayetzav Moshe veziqnei Yisrael et-ha'am lemor shamor et-kol-hamitzvah asher anochi metzaveh etchem hayom</strong> (<em>wayyĕṣaw mōšê wĕziqnê yiśrāʾēl ʾet-hāʿām lēʾmōr šāmôr ʾet-kol-hammiṣwâ ʾăšer ʾānōḵî mĕṣawwê ʾetḵem hayyôm</em>): Moses and the elders of Israel command the people to keep all the commandment this day. The plural authority — Moses <em>and</em> the elders — signals the beginning of the covenant ratification ceremony that will be performed at Shechem (between Gerizim and Ebal). The <em>ziqnei Yisrael</em> (elders of Israel) act as co-commanders, representing the people's representative leadership structures that will persist after Moses' death. The ceremony is prospective but commanded now — obedience is not waiting for entry but is already demanded.</p>",
    "2": "<p><strong>vehayah beyom asher ta'avru et-haYarden el-ha'aretz asher YHWH Eloheicha noten lach vahaqimota lecha avanim gedolot vesadta otam beshid</strong> (<em>wĕhāyâ b̠ayyôm ʾăšer taʿăb̠rû ʾet-hayyardēn ʾel-hāʾāreṣ ʾăšer Yhwh ʾĕlōhêkā nōtēn lāk wĕhăqîmōtā lĕkā ʾăb̠ānîm gĕdōlôt wĕśadtā ʾôtām b̠aśśîḏ</em>): 'And on the day you cross the Jordan to the land that the LORD your God is giving you, you shall set up large stones and plaster them with plaster.' <em>Avanim gedolot</em> (great/large stones): standing stones as monuments and law-carriers. <em>Sadta otam beshid</em> (plaster them with plaster): the inscribed law is made durable and public — plastered steles were a known ancient practice (cf. the Karnak reliefs and Amarna correspondence). The Jordan crossing is the threshold event; the monument is to be raised on the same day — immediacy signals the covenant's urgency.</p>",
    "3": "<p><strong>vekatavta aleihem et-kol-divrei hatorah hazot be'ovrecha lema'an asher tavo el-ha'aretz asher YHWH Eloheicha noten lach eretz zavat chalav udvash ka'asher diber YHWH Elohi avoteicha lach</strong> (<em>wĕkātab̠tā ʿălêhem ʾet-kol-dibrê hattôrāh hazzōʾt b̠ĕʿob̠rĕkā lĕmaʿan ʾăšer tāb̠ōʾ ʾel-hāʾāreṣ ʾăšer Yhwh ʾĕlōhêkā nōtēn lāk ʾereṣ zāb̠at ḥālāb̠ ûd̠ĕb̠aš kāʾăšer dib̠ber Yhwh ʾĕlōhê ʾăb̠ôtêkā lāk</em>): Write on the stones all the words of this law when you cross over, so that you may enter the land YHWH your God is giving you, a land of milk and honey as he promised. The writing of the law is the precondition for inhabiting the land. <em>Kol-divrei hatorah hazot</em> (all the words of this law): the totality of the covenant document — not a selection but the complete <em>Torah</em> — is to be publicly inscribed. The law is not esoteric or priestly property but a public text accessible to all.</p>",
    "4": "<p><strong>vehayah be'ovretchem et-haYarden taqimu et-ha'avanim ha'eleh asher anochi metzaveh etchem hayom behar Eival vesadta otam beshid</strong> (<em>wĕhāyâ b̠ĕʿob̠rĕḵem ʾet-hayyardēn tāqîmû ʾet-hāʾăb̠ānîm hāʾēllê ʾăšer ʾānōḵî mĕṣawwê ʾetḵem hayyôm b̠ĕhar ʿêb̠āl wĕśadtā ʾôtām b̠aśśîḏ</em>): Set up these stones on mount Ebal — the mountain of cursing. The choice of <em>Eival</em> (Ebal) for the inscription is theologically provocative: the law is written on the mountain of curses, not the mountain of blessings. This sequence underscores that the Torah's primary function in the fallen human condition is to expose transgression (cf. Rom 3:20; Gal 3:19) — the law reveals the curse before it reveals the path to blessing. The Samaritan Pentateuch reads <em>Gerizim</em> here (a textual variant driven by Samaritan interests in their sacred mountain).</p>",
    "6": "<p><strong>avanim shelemot tibne et-mizbach YHWH Eloheicha veha'alita alav olot l'YHWH Eloheicha</strong> (<em>ʾăb̠ānîm šĕlēmôt tib̠nê ʾet-mizbēaḥ Yhwh ʾĕlōhêkā wĕhaʿălîtā ʿālāyw ʿōlōt lYhwh ʾĕlōhêkā</em>): 'You shall build the altar of the LORD your God with whole stones, and offer burnt offerings on it to the LORD your God.' <em>Avanim shelemot</em> (whole stones, complete/sound stones): the same principle as v5's prohibition of iron tools — the altar must be built with natural, unworked stones. <em>Shalem</em> (whole, complete, at peace) shares a root with <em>shalom</em>; the altar's wholeness mirrors the peace it facilitates. <em>Olot</em> (burnt offerings, whole offerings): the <em>olah</em> is entirely consumed on the altar — the first offering on the Ebal altar is one of total consecration.</p>",
    "7": "<p><strong>vezavachta shelamim ve'achalta sham vesimachta lifnei YHWH Eloheicha</strong> (<em>wĕzāb̠aḥtā šĕlāmîm wĕʾāḵaltā šām wĕśāmaḥtā lip̄nê Yhwh ʾĕlōhêkā</em>): 'And you shall offer peace offerings and shall eat there, and you shall rejoice before the LORD your God.' <em>Shelamim</em> (peace offerings, shared offerings): unlike the <em>olah</em> (entirely burned), the <em>shelamim</em> are shared between the altar (fat portions), the priests, and the worshipper's household — a communion meal in divine presence. <em>Vesimachta</em> (you shall rejoice): on the mountain of curses, after the law is inscribed and the offerings made, covenant joy is commanded. The sequence — law inscription → whole burnt offering → shared communion meal → joy — is the covenant pattern: accountability, consecration, reconciliation, celebration.</p>",
    "8": "<p><strong>uchtavta al-ha'avanim et kol-divrei hatorah hazot be'er heitiv</strong> (<em>ûḵtab̠tā ʿal-hāʾăb̠ānîm ʾet kol-dibrê hattôrāh hazzōʾt b̠āʾēr hêṭēb̠</em>): 'And you shall write on the stones all the words of this law very plainly.' <em>Be'er heitiv</em> (very plainly, making it plain and clear): <em>be'er</em> from <em>ba'ar</em> — to explain, to make clear, to engrave. The Septuagint translates <em>saphōs</em> (clearly). The word <em>deuteronomion</em> in the Septuagint's name for this book comes from a related phrase in 17:18 (<em>mishneh hatorah hazot</em> — a copy/repetition of this law); here the law is written <em>plainly</em> so that all who pass may read it without priestly mediation. The publicness of the Torah is a mark of its covenant character.</p>",
    "9": "<p><strong>vayedaber Moshe vehakohanim haLevi'im el-kol-Yisrael lemor hasket ushma Yisrael hayom hazeh nihyeita le'am l'YHWH Eloheicha</strong> (<em>waydab̠bēr mōšê wĕhakkōhănîm hălĕwiyyim ʾel-kol-yiśrāʾēl lēʾmōr hasqēt ûšmaʿ yiśrāʾēl hayyôm hazzê nihyêtā lĕʿam lYhwh ʾĕlōhêkā</em>): 'Then Moses and the Levitical priests said to all Israel, Keep silence and hear, O Israel: this day you have become the people of the LORD your God.' <em>Hasket</em> (keep silence, be still, pay attention): a strong command for attentive listening. <em>Nihyeita le'am</em> (you have become a people): the covenant constitution is being publicly ratified — in this ceremonial moment, the covenant relationship is formally enacted. The Levitical priests speak alongside Moses, signaling the priestly mediation of Torah that will continue after Moses' death.</p>",
    "10": "<p><strong>ushama'ta beqol YHWH Eloheicha ve'asita et-mitzvotav ve'et-chuqqav asher anochi metzavecha hayom</strong> (<em>ûšāmaʿtā b̠ĕqôl Yhwh ʾĕlōhêkā wĕʿāśîtā ʾet-miṣwōtāyw wĕʾet-ḥuqqāyw ʾăšer ʾānōḵî mĕṣawwĕkā hayyôm</em>): 'You shall therefore obey the voice of the LORD your God, keeping his commandments and his statutes, which I command you today.' <em>Shama' beqol</em> (hear, obey the voice): <em>shema</em> with the preposition <em>be</em> — to listen into, to act upon hearing. The <em>Shema</em> pattern is repeated: hearing is the mode of covenant relationship; obedience is the content of hearing. The verse functions as the response to the proclamation of v9 — the newly constituted people's obligation immediately follows their constitution.</p>",
    "11": "<p><strong>vayetzav Moshe et-ha'am bayom hahu lemor</strong> (<em>wayyĕṣaw mōšê ʾet-hāʿām bayyôm hahûʾ lēʾmōr</em>): 'And Moses commanded the people on that day, saying.' A brief hinge verse introducing the tribal assignment for the Gerizim-Ebal ceremony. <em>Bayom hahu</em> (on that day): the ceremony is tied to the specific day of crossing — the ratification of the covenant in Canaan is not deferred. Moses' authoritative command allocates the tribes to their positions, ensuring the ceremony's order is divinely specified rather than improvised.</p>",
    "12": "<p><strong>eleh ya'amdu levarech et-ha'am al-har Gerizim be'ovretchem et-haYarden Shimon veLevi viYhudah veYissachar veYosef uvBinyamin</strong> (<em>ʾēllê yaʿamdû lĕb̠ārēk ʾet-hāʿām ʿal-har gĕrizzîm b̠ĕʿob̠rĕḵem ʾet-hayyardēn šimʿôn wĕlēwî wîhûdâ wĕyiśśāḵār wĕyôsēp̄ ûb̠inyāmîn</em>): 'These shall stand on mount Gerizim to bless the people when you have crossed the Jordan: Simeon, Levi, Judah, Issachar, Joseph, and Benjamin.' Six tribes on Gerizim (blessing): note that both Levi and Joseph (Ephraim/Manasseh) are among the blessing-tribes — Levi here as the priestly mediator, Joseph as the double-portioned heir. The assignment is not by geographic proximity or birth order — it follows a theological logic that later commentators have debated (e.g., the Rachel-and-Leah tribal groupings).</p>",
    "13": "<p><strong>ve'eleh ya'amdu al-haqelalah behar Eival Reuven Gad ve'Asher uZevulun Dan veNaftali</strong> (<em>wĕʾēllê yaʿamdû ʿal-haqqĕlālâ b̠ĕhar ʿêb̠āl rĕʾûb̠ēn gāḏ wĕʾāšēr ûzĕb̠ûlun dān wĕnap̄tālî</em>): 'And these shall stand for the curse on mount Ebal: Reuben, Gad, Asher, Zebulun, Dan, and Naphtali.' Six tribes on Ebal (curse). Reuben stands on the curse-side despite being the firstborn — his disqualification (Gen 35:22; 49:3-4) shadows him even in the ceremony. <em>Al-haqelalah</em> (for the curse, over the curse): the tribes do not themselves curse but stand as witnesses and responders to the curses proclaimed by the Levites below (vv. 14-26). The geographic staging — twin mountains facing each other — dramatizes the covenant's binary: blessing or curse, obedience or disobedience.</p>",
    "14": "<p><strong>ve'anu haLevi'im ve'amru el-kol-ish Yisrael qol ram</strong> (<em>wĕʿānû hallĕwiyyim wĕʾāmrû ʾel-kol-ʾîš yiśrāʾēl qôl rām</em>): 'And the Levites shall declare to all the men of Israel with a loud voice.' <em>Qol ram</em> (a high/loud voice): the curses are proclaimed audibly, publicly, across the valley between the two mountains — the volume ensures that all Israel hears and cannot claim ignorance. The Levites' mediating role (cf. v9) is here performative: they enact the covenant ceremony by declaration. The use of <em>qol ram</em> anticipates the Mishnaic description of the ceremony as a liturgical responsory (m. Sotah 7:5).</p>",
    "15": "<p><strong>arur ha'ish asher ya'aseh pesel umasechah to'avat YHWH ma'aseh yedei charash veSam basater ve'anu kol-ha'am ve'amru Amen</strong> (<em>ʾārûr hāʾîš ʾăšer yaʿăśê p̄esel ûmasēḵâ tôʿăb̠at Yhwh maʿăśê yĕdê ḥārāš wĕśām bassēter wĕʿānû kol-hāʿām wĕʾāmrû ʾāmēn</em>): 'Cursed be the man who makes a carved or cast metal image, an abomination to the LORD, a thing made by the hands of a craftsman, and sets it up in secret. And all the people shall answer and say, Amen.' The dodecalogue of curses (vv. 15-26) begins with idolatry — the foundational covenant violation. <em>Arur</em> (cursed): a performative declaration of exclusion from covenant blessing. <em>Basater</em> (in secret): the curse specifically targets hidden idolatry — public apostasy could be addressed by courts, but the <em>arur</em> curses penetrate what human courts cannot see. The communal <em>Amen</em> is the congregation's self-imprecation: each person accepts the curse as applicable to themselves should they commit this act.</p>",
    "16": "<p><strong>arur meqalel aviv ve'imo ve'amar kol-ha'am Amen</strong> (<em>ʾārûr mĕqallēl ʾāb̠îw wĕʾimmô wĕʾāmar kol-hāʿām ʾāmēn</em>): 'Cursed be anyone who dishonors his father or his mother. And all the people shall say, Amen.' <em>Meqalel</em> (dishonors, treats lightly, curses): from <em>qalal</em> — to be light, to treat as worthless, the opposite of <em>kaved</em> (to honor, to make heavy/weighty — cf. the Fifth Commandment, Deut 5:16). The curse again targets the hidden act: public dishonoring of parents could be prosecuted under the law (21:18-21), but the <em>arur</em> addresses contempt that is performed in secret or through subtle patterns of neglect.</p>",
    "17": "<p><strong>arur masig gevul re'ehu ve'amar kol-ha'am Amen</strong> (<em>ʾārûr massîg gĕb̠ûl rēʿēhû wĕʾāmar kol-hāʿām ʾāmēn</em>): 'Cursed be anyone who moves his neighbor's landmark. And all the people shall say, Amen.' <em>Masig gevul</em> (moves a boundary marker, encroaches on a landmark): <em>gevul</em> is a property boundary — the stone markers that defined land allotments in Israel. Moving them was a secret act of theft that also violated the covenant's land theology: the land was YHWH's gift allocated to each family by lot; encroaching on a neighbor's allotment was encroaching on what YHWH had given them. Cf. Prov 22:28; 23:10; Job 24:2.</p>",
    "18": "<p><strong>arur mashgeh iver baderech ve'amar kol-ha'am Amen</strong> (<em>ʾārûr mašgê ʿiwwēr b̠addāreḵ wĕʾāmar kol-hāʿām ʾāmēn</em>): 'Cursed be anyone who misleads a blind person on the road. And all the people shall say, Amen.' <em>Mashgeh iver</em> (makes the blind wander/go astray): from <em>shagah</em> — to lead astray, to cause to err. The blind person's inability to verify the directions given makes them wholly dependent on the guide's honesty. Leviticus 19:14 prohibits this in positive form: 'you shall not put a stumbling block before the blind.' The vulnerability of the disabled creates an obligation of care that the law enforces through the covenant curse.</p>",
    "19": "<p><strong>arur mateh mishpat ger yatom ve'almanah ve'amar kol-ha'am Amen</strong> (<em>ʾārûr maṭṭê mišpaṭ gēr yātôm wĕʾalmānâ wĕʾāmar kol-hāʿām ʾāmēn</em>): 'Cursed be anyone who perverts the justice due to the sojourner, the fatherless, and the widow. And all the people shall say, Amen.' <em>Mateh mishpat</em> (perverts justice, bends the judgment): <em>natah</em> in the Hiphil — to cause to turn aside, to deflect what is straight. The three parties again: <em>ger</em>, <em>yatom</em>, <em>almanah</em> — those without legal advocates in a patriarchal society. Judicial perversion of their cases would be done secretly (bribed judges, false witnesses) — making it a prime candidate for the <em>arur</em> curses. The prophets return repeatedly to this violation as evidence of covenant failure (Isa 1:17, 23; Jer 7:6; Zech 7:10).</p>",
    "20": "<p><strong>arur shochev im-eshet aviv ki gilah kenaf aviv ve'amar kol-ha'am Amen</strong> (<em>ʾārûr šōḵēb̠ ʿim-ʾēšet ʾāb̠îw kî gillâ kĕnap̄ ʾāb̠îw wĕʾāmar kol-hāʿām ʾāmēn</em>): 'Cursed be anyone who lies with his father's wife, because he has uncovered his father's nakedness. And all the people shall say, Amen.' <em>Eshet aviv</em> (his father's wife): includes the stepmother — any wife of the father, not necessarily the man's own mother. <em>Gilah kenaf aviv</em> (he has uncovered his father's skirt/wing): sexual union with a wife is expressed as being under her husband's protective wing (<em>kanaf</em>, cf. Ruth 3:9; Ezek 16:8). To lie with the father's wife is to usurp the father's authority and violate his most intimate boundary — echoing Reuben's disqualification (Gen 35:22; 49:4).</p>",
    "21": "<p><strong>arur shochev im-kol-behemah ve'amar kol-ha'am Amen</strong> (<em>ʾārûr šōḵēb̠ ʿim-kol-bĕhēmâ wĕʾāmar kol-hāʿām ʾāmēn</em>): 'Cursed be anyone who lies with any kind of animal. And all the people shall say, Amen.' Prohibited in Lev 18:23 and 20:15-16, this act violates the order of creation (species boundaries established at Genesis 1) as well as the covenant code. Its inclusion in the Ebal curses signals its deep violation of the created order that the covenant is designed to uphold. The universality of <em>kol-behemah</em> (any animal) leaves no exceptions.</p>",
    "22": "<p><strong>arur shochev im-achoto bat-aviv o vat-imo ve'amar kol-ha'am Amen</strong> (<em>ʾārûr šōḵēb̠ ʿim-ʾăḥōtô b̠at-ʾāb̠îw ʾô b̠at-ʾimmô wĕʾāmar kol-hāʿām ʾāmēn</em>): 'Cursed be anyone who lies with his sister, whether the daughter of his father or the daughter of his mother. And all the people shall say, Amen.' The curse covers both full sisters and half-sisters (paternal and maternal) — Abraham's marriage to his half-sister Sarah (Gen 20:12) belongs to the pre-Sinai era; the covenant code established at Sinai (Lev 18:9, 11) prohibits it and the Deuteronomic curse ratifies that prohibition. The double specification (daughter of father or of mother) closes the definitional loophole Abraham's case might suggest.</p>",
    "23": "<p><strong>arur shochev im-chamotoh ve'amar kol-ha'am Amen</strong> (<em>ʾārûr šōḵēb̠ ʿim-ḥămôtô wĕʾāmar kol-hāʿām ʾāmēn</em>): 'Cursed be anyone who lies with his mother-in-law. And all the people shall say, Amen.' The prohibition in Lev 18:17 and 20:14 covers this: the mother-in-law relationship creates affinity (the covenant of marriage makes the mother of one's spouse a quasi-mother). The violation would typically occur in household proximity — a hidden act that courts could not easily prosecute but the <em>arur</em> formula reaches.</p>",
    "24": "<p><strong>arur makeh re'ehu basater ve'amar kol-ha'am Amen</strong> (<em>ʾārûr makkê rēʿēhû bassēter wĕʾāmar kol-hāʿām ʾāmēn</em>): 'Cursed be anyone who strikes down his neighbor in secret. And all the people shall say, Amen.' <em>Makeh re'ehu basater</em> (strikes his neighbor secretly): <em>nakah</em> in the Hiphil — to strike down, possibly fatally. <em>Bassater</em> (in secret) is the key qualifier: public killing could be prosecuted by the avenger of blood and the elders; secret assassination evades human justice. The curse invokes YHWH as the ultimate witness to concealed violence — the covenant's eye penetrates where human courts cannot see.</p>",
    "25": "<p><strong>arur loqeach shochad lehakot nefesh dam naki ve'amar kol-ha'am Amen</strong> (<em>ʾārûr lōqēaḥ šōḥad lĕhakkôt nep̄eš dām nāqî wĕʾāmar kol-hāʿām ʾāmēn</em>): 'Cursed be anyone who takes a bribe to shed innocent blood. And all the people shall say, Amen.' <em>Shochad</em> (bribe): the repeated prohibition of bribery in Deuteronomy (cf. 16:19; 27:25) targets the corruption of the justice system at its point of highest vulnerability — paid witnesses or hired assassins. <em>Dam naki</em> (innocent blood): the blood of the wrongfully killed cries out (Gen 4:10) and defiles the land (Num 35:33-34). The curse against bribe-murder thus protects both covenant justice and the land's purity. Paul's citation of Deut 27:26 (the next verse) in Gal 3:10 implicitly encompasses all these specific curses as evidence of universal human failure under the law.</p>"
  }
}

def main():
    existing = load_comm('original', 'deuteronomy')
    merge_comm(existing, DEUT)
    save_comm('original', 'deuteronomy', existing)
    print('Deuteronomy 26-27 original fill: 41 verses written.')

if __name__ == '__main__':
    main()
